import{_ as a,o as t,c as i,a2 as n}from"./chunks/framework.OWFDNrRT.js";const u=JSON.parse('{"title":"ADR-005: ECS Integration Strategy","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-005-ecs-integration-strategy.md","filePath":"adr/ADR-005-ecs-integration-strategy.md","lastUpdated":1773459185000}'),s={name:"adr/ADR-005-ecs-integration-strategy.md"};function o(r,e,l,c,d,h){return t(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="adr-005-ecs-integration-strategy" tabindex="-1">ADR-005: ECS Integration Strategy <a class="header-anchor" href="#adr-005-ecs-integration-strategy" aria-label="Permalink to &quot;ADR-005: ECS Integration Strategy&quot;">​</a></h1><p><strong>Status</strong>: Accepted <strong>Date</strong>: 2026-03-09 <strong>Deciders</strong>: kooshapari</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>DINO uses Unity ECS with Burst compilation. Community guidance explicitly warns that:</p><ol><li>The BepInEx loader for DINO uses a modified setup with <code>BepInEx/ecs_plugins/</code> path</li><li>Harmony-based patching has severe performance costs (removing Burst-generated DLL halves frame rate)</li><li>ECS-native modding is the recommended path</li><li>There is no official API documentation</li><li>The existing mod ecosystem is small (~handful of Nexus mods)</li></ol><p>Sources: Steam Community guide (id:3348001330), Nexus Mods DINO page.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="ecs-native-over-harmony" tabindex="-1">ECS-Native Over Harmony <a class="header-anchor" href="#ecs-native-over-harmony" aria-label="Permalink to &quot;ECS-Native Over Harmony&quot;">​</a></h3><p>Prefer writing ECS-based mods directly over Harmony method patching. Harmony is allowed only as a last resort for systems that cannot be reached through ECS.</p><h3 id="isolation-architecture" tabindex="-1">Isolation Architecture <a class="header-anchor" href="#isolation-architecture" aria-label="Permalink to &quot;Isolation Architecture&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Mod Packs] --&gt; [SDK/Registries] --&gt; [Runtime Integration Layer] --&gt; [DINO ECS]</span></span>
<span class="line"><span>                                            ^</span></span>
<span class="line"><span>                                    (Isolated, version-sensitive,</span></span>
<span class="line"><span>                                     fewest agents touch this)</span></span></code></pre></div><p>The Runtime Integration Layer is:</p><ul><li>The ugliest, most brittle part</li><li>Handles BepInEx/ECS bootstrapping, entity queries, prefab replacement, component patching, stat injection</li><li>Version-gated against specific DINO builds</li><li>Treated as unstable and highly version-sensitive</li></ul><h3 id="performance-rules" tabindex="-1">Performance Rules <a class="header-anchor" href="#performance-rules" aria-label="Permalink to &quot;Performance Rules&quot;">​</a></h3><ul><li>No per-entity heavy patch logic every frame</li><li>Patch systems, not individual objects</li><li>Cache ECS queries</li><li>Batch stat application</li><li>Avoid Harmony hot paths unless proven safe</li></ul><h3 id="version-compatibility" tabindex="-1">Version Compatibility <a class="header-anchor" href="#version-compatibility" aria-label="Permalink to &quot;Version Compatibility&quot;">​</a></h3><ul><li>Maintain component dumps per game version</li><li>Version gate runtime hooks</li><li>Provide fallback/degradation when hooks break</li><li>Auto-detect game version at bootstrap</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li>Runtime layer is small, isolated, touched by few agents</li><li>SDK consumers never interact with raw ECS</li><li>Game updates break Runtime layer only, not pack content</li><li>Performance remains viable for large-scale mods</li><li>Reverse engineering investment is captured and reused</li></ul>`,19)])])}const m=a(s,[["render",o]]);export{u as __pageData,m as default};
